@namespace Lumeo

<nav role="navigation" aria-label="pagination" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</nav>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"mx-auto flex w-full justify-center {Class}".Trim();
}

@namespace Lumeo

<ul class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</ul>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex flex-row items-center gap-1 {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <span class="@CssClass" @attributes="AdditionalAttributes">
        <Blazicon Svg="Lucide.Ellipsis" class="h-4 w-4" />
        <span class="sr-only">@L["Pagination.MorePages"]</span>
    </span>
</li>

@code {
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"flex h-9 w-9 items-center justify-center {Class}".Trim();
}

@namespace Lumeo

<li>
    <button class="@CssClass" @onclick="OnClick" @attributes="AdditionalAttributes">
        @ChildContent
    </button>
</li>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 h-9 w-9 {(IsActive ? "border border-input bg-background shadow-sm" : "hover:bg-accent hover:text-accent-foreground")} {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <button class="@CssClass" @onclick="OnClick" disabled="@Disabled" @attributes="AdditionalAttributes">
        <span>@L["Pagination.Next"]</span>
        <Blazicon Svg="Lucide.ChevronRight" class="h-4 w-4" />
    </button>
</li>

@code {
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex items-center justify-center gap-1 whitespace-nowrap rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground h-9 px-3 disabled:pointer-events-none disabled:opacity-50 {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <button class="@CssClass" @onclick="OnClick" disabled="@Disabled" @attributes="AdditionalAttributes">
        <Blazicon Svg="Lucide.ChevronLeft" class="h-4 w-4" />
        <span>@L["Pagination.Previous"]</span>
    </button>
</li>

@code {
    [Parameter] public EventCallback OnClick { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"inline-flex items-center justify-center gap-1 whitespace-nowrap rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground h-9 px-3 disabled:pointer-events-none disabled:opacity-50 {Class}".Trim();
}
